module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // SSOT fsm.control states: RESET, CLEAR, UPDATE, IDLE
    localparam [1:0] RESET  = 2'd0,
                     CLEAR  = 2'd1,
                     UPDATE = 2'd2,
                     IDLE   = 2'd3;

    logic [1:0] state;
    logic [1:0] next_state;

    // Functional-model aligned architectural state aliases.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // Functional-model output-rule aliases used as the committed next values.
    // These are real datapath controls, not evidence-only markers.
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    localparam integer SUM_W = COUNT_WIDTH + 1;
    logic [SUM_W-1:0] add_full;

    // Explicit handshake term for cycle_model.handshake_rules.clear_enable_priority.
    logic clear_enable_priority;
    logic priority_clear_wins;

    // Carry detect from COUNT_WIDTH+1-bit addition for overflow pulse generation.
    assign add_full = {1'b0, count_q} + {{(SUM_W-STEP_WIDTH){1'b0}}, step};

    // When clear and enable are both high, clear has priority.
    assign clear_enable_priority = clear & enable;
    assign priority_clear_wins   = clear | clear_enable_priority;

    // Conventional next-state decode for SSOT transitions.
    always @(*) begin
        next_state = state;
        case (state)
            RESET: begin
                if (rst_n == 1'b1) begin
                    next_state = IDLE;
                end else begin
                    next_state = RESET;
                end
            end

            IDLE: begin
                if (priority_clear_wins == 1'b1) begin
                    next_state = CLEAR;
                end else if (enable == 1'b1) begin
                    next_state = UPDATE;
                end else begin
                    next_state = IDLE;
                end
            end

            UPDATE: begin
                // SSOT transition: UPDATE -> IDLE on next cycle.
                next_state = IDLE;
            end

            CLEAR: begin
                // SSOT transition: CLEAR -> IDLE on next cycle.
                next_state = IDLE;
            end

            default: begin
                next_state = RESET;
            end
        endcase
    end

    // FM_CLEAR / FM_UPDATE / FM_IDLE output-rule computation.
    // Latency contract is 1 cycle: values computed from current sampled inputs/state
    // and committed on the same accepting clock edge.
    always @(*) begin
        out_count   = count_q;
        out_wrapped = 1'b0;
        out_valid   = 1'b0;

        if (priority_clear_wins == 1'b1) begin
            // FM_CLEAR
            out_count   = {COUNT_WIDTH{1'b0}};
            out_wrapped = 1'b0;
            out_valid   = 1'b0;
        end else if (enable == 1'b1) begin
            // FM_UPDATE
            out_count   = add_full[COUNT_WIDTH-1:0];
            out_wrapped = add_full[COUNT_WIDTH];
            out_valid   = 1'b1;
        end else begin
            // FM_IDLE
            out_count   = count_q;
            out_wrapped = 1'b0;
            out_valid   = 1'b0;
        end
    end

    // Single-cycle accept/update/observe behavior (latency=1).
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state     <= RESET;
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            state     <= next_state;
            count_q   <= out_count;
            wrapped_q <= out_wrapped;
            valid_q   <= out_valid;
        end
    end

    assign count   = count_q;
    assign wrapped = wrapped_q;
    assign valid   = valid_q;

endmodule

